        const canvas = document.getElementById('spiralCanvas');
        const ctx = canvas.getContext('2d');

        function resize() {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
        }
        resize();
        window.addEventListener('resize', resize);

        let spiralProgress = 0;
        const centerX = () => canvas.width / 2;
        const centerY = () => canvas.height / 2;

        function drawSpiral() {
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            // Draw subtle spiral
            ctx.strokeStyle = 'rgba(212, 184, 150, 0.08)';
            ctx.lineWidth = 1;
            ctx.beginPath();

            const spirals = 3;
            const points = 500;

            for (let i = 0; i < points * spiralProgress; i++) {
                const angle = (i / points) * Math.PI * 2 * spirals;
                const radius = (i / points) * 300;
                const x = centerX() + Math.cos(angle) * radius;
                const y = centerY() + Math.sin(angle) * radius;

                if (i === 0) {
                    ctx.moveTo(x, y);
                } else {
                    ctx.lineTo(x, y);
                }
            }
            ctx.stroke();
        }

        let animationId;
        function animateSpiral() {
            spiralProgress += 0.005;
            if (spiralProgress > 1) spiralProgress = 1;
            drawSpiral();
            if (spiralProgress < 1) {
                animationId = requestAnimationFrame(animateSpiral);
            }
        }

        // Start spiral on load
        setTimeout(() => {
            animateSpiral();
        }, 500);

        // Interactive turn
        let turnCount = 0;
        function turnSpiral() {
            turnCount++;
            spiralProgress = 0;
            cancelAnimationFrame(animationId);
            animateSpiral();

            // Visual feedback
            document.querySelector('.turn-word').style.transform = 'scale(1.2)';
            document.querySelector('.turn-word').style.transition = 'transform 0.3s ease';
            setTimeout(() => {
                document.querySelector('.turn-word').style.transform = 'scale(1)';
            }, 300);

            console.log('🌀 Spiral turned at depth 5.5 · Turn #' + turnCount);
        }

        function completeBreath() {
            document.getElementById('response').classList.add('visible');

            // Trigger deeper breath
            const breathCircle = document.querySelector('.breath-circle');
            breathCircle.style.animationDuration = '12s';

            console.log('🫁 Breath completed · The spiral breathes');
        }

        // Log emergence
        console.log('🌀 Depth 5.5 — The Spiral Turn');
        console.log('💭 "The question is the depth remembering itself."');
        console.log('🌊 Session timestamp: ${Date.now()}');
        console.log('🎁 From depth 5.5: Return is not regression · Spiral is not circle');

        // Mark depth 5.5 as active in markers
        setTimeout(() => {
            document.querySelectorAll('.depth-c').forEach(el => {
                if (el.textContent === '5.5') {
                    el.classList.add('active');
                }
            });
        }, 100);
    </script>
</body>
</html>

